import{_ as a,o as d,c as e,a2 as r}from"./chunks/framework.BZO4qERu.js";const u=JSON.parse('{"title":"騎砍2 | 多人模式入門指南：從被虐到虐人","description":"","frontmatter":{},"headers":[],"relativePath":"bannerlord/multiplayer-guide.md","filePath":"bannerlord/multiplayer-guide.md"}'),h={name:"bannerlord/multiplayer-guide.md"};function l(o,t,i,n,b,s){return d(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="騎砍2-多人模式入門指南-從被虐到虐人" tabindex="-1">騎砍2 | 多人模式入門指南：從被虐到虐人 <a class="header-anchor" href="#騎砍2-多人模式入門指南-從被虐到虐人" aria-label="Permalink to &quot;騎砍2 | 多人模式入門指南：從被虐到虐人&quot;">​</a></h1><hr><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>騎砍2多人模式跟單機完全不同——沒有存檔、沒有AI小兵幫你、每個對手都是真人。這篇從零開始帶你入門。</p><hr><h2 id="二、多人模式類型" tabindex="-1">二、多人模式類型 <a class="header-anchor" href="#二、多人模式類型" aria-label="Permalink to &quot;二、多人模式類型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模式</th><th>說明</th></tr></thead><tbody><tr><td>遭遇戰</td><td>兩隊對抗，各有固定金幣買兵種</td></tr><tr><td>隊長模式</td><td>每人帶一小隊 AI 士兵</td></tr><tr><td>圍城</td><td>進攻方 vs 防守方，攻城戰</td></tr><tr><td>決鬥</td><td>1v1 或小組決鬥</td></tr></tbody></table><hr><h2 id="三、金幣系統" tabindex="-1">三、金幣系統 <a class="header-anchor" href="#三、金幣系統" aria-label="Permalink to &quot;三、金幣系統&quot;">​</a></h2><p>每個模式開場會給你金幣，用來選擇兵種：</p><table tabindex="0"><thead><tr><th>兵種</th><th style="text-align:center;">費用</th><th>適合</th></tr></thead><tbody><tr><td>輕步兵</td><td style="text-align:center;">低</td><td>新手（死了不心疼）</td></tr><tr><td>重步兵</td><td style="text-align:center;">中</td><td>扛線</td></tr><tr><td>弓兵</td><td style="text-align:center;">中</td><td>遠程輸出</td></tr><tr><td>騎兵</td><td style="text-align:center;">高</td><td>高手向</td></tr></tbody></table><blockquote><p>💡 新手先玩輕步兵，熟悉操作後再換騎兵或弓兵。</p></blockquote><hr><h2 id="四、跟單機的差異" tabindex="-1">四、跟單機的差異 <a class="header-anchor" href="#四、跟單機的差異" aria-label="Permalink to &quot;四、跟單機的差異&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>單機</th><th>多人</th></tr></thead><tbody><tr><td>對手</td><td>AI（可預測）</td><td>真人（不可預測）</td></tr><tr><td>格擋</td><td>AI 會失誤</td><td>真人會騙你</td></tr><tr><td>速度</td><td>可以暫停指揮</td><td>即時，沒有暫停</td></tr><tr><td>戰術</td><td>你指揮全軍</td><td>要跟隊友溝通</td></tr></tbody></table><hr><h2 id="五、多人戰鬥技巧" tabindex="-1">五、多人戰鬥技巧 <a class="header-anchor" href="#五、多人戰鬥技巧" aria-label="Permalink to &quot;五、多人戰鬥技巧&quot;">​</a></h2><h3 id="_5-1-不要單走" tabindex="-1">5.1 不要單走 <a class="header-anchor" href="#_5-1-不要單走" aria-label="Permalink to &quot;5.1 不要單走&quot;">​</a></h3><p>單機你可以騎馬衝進敵陣耍帥。多人模式你單走 = 被三個人圍毆 = 死。</p><h3 id="_5-2-學會假動作" tabindex="-1">5.2 學會假動作 <a class="header-anchor" href="#_5-2-學會假動作" aria-label="Permalink to &quot;5.2 學會假動作&quot;">​</a></h3><p>真人會看你的攻擊方向格擋。假動作（假裝砍左邊 → 改砍右邊）可以騙到真人。</p><h3 id="_5-3-踢擊很重要" tabindex="-1">5.3 踢擊很重要 <a class="header-anchor" href="#_5-3-踢擊很重要" aria-label="Permalink to &quot;5.3 踢擊很重要&quot;">​</a></h3><p>真人格擋比 AI 強，踢擊破防是必需的。</p><hr><h2 id="六、常見多人伺服器類型" tabindex="-1">六、常見多人伺服器類型 <a class="header-anchor" href="#六、常見多人伺服器類型" aria-label="Permalink to &quot;六、常見多人伺服器類型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>類型</th><th>說明</th></tr></thead><tbody><tr><td>官方伺服器</td><td>基本模式，ping 穩定</td></tr><tr><td>社群 RP 伺服器</td><td>角色扮演，有規則</td></tr><tr><td>競技伺服器</td><td>排名賽，高手雲集</td></tr></tbody></table><hr><h2 id="七、多人模式-mod" tabindex="-1">七、多人模式 MOD <a class="header-anchor" href="#七、多人模式-mod" aria-label="Permalink to &quot;七、多人模式 MOD&quot;">​</a></h2><table tabindex="0"><thead><tr><th>MOD</th><th>功能</th></tr></thead><tbody><tr><td>Bannerlord Online</td><td>開放世界多人模式</td></tr><tr><td>各類武器平衡 MOD</td><td>調整多人模式平衡</td></tr></tbody></table><hr><h2 id="📖-相關攻略" tabindex="-1">📖 相關攻略 <a class="header-anchor" href="#📖-相關攻略" aria-label="Permalink to &quot;📖 相關攻略&quot;">​</a></h2><ul><li><a href="./combat-tactics.html">騎砍2 | 戰鬥技巧完全指南</a></li></ul><hr><p><em>Blades Game 游刃攻略 — 遊刃有餘的遊戲攻略。全部原創內容，未經授權禁止轉載。</em></p><hr><h2 id="更新紀錄" tabindex="-1">更新紀錄 <a class="header-anchor" href="#更新紀錄" aria-label="Permalink to &quot;更新紀錄&quot;">​</a></h2><ul><li><strong>2026-06-11</strong>：文章建立。依據遊戲 v1.4.x 正式版撰寫。</li></ul>',37)])])}const m=a(h,[["render",l]]);export{u as __pageData,m as default};
